package main

import (
	"fmt"
	"strings"
	"time"

	"github.com/beego/beego/v2/client/orm"
)

type UserProfile struct {
	Id          int64     `orm:"column(id);pk;auto"`
	Username    string    `orm:"column(username);unique"`
	DisplayName string    `orm:"column(display_name)"`
	Email       string    `orm:"column(email)"`
	Department  string    `orm:"column(department)"`
	Role        string    `orm:"column(role)"`
	CreatedAt   time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivity struct {
	Id         int64     `orm:"column(id);pk;auto"`
	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	placeholders := make([]string, len(usernames))
	for i := range placeholders {
		placeholders[i] = "?"
	}

	query := fmt.Sprintf(`
		SELECT 
			u.display_name as display_name,
			a.action_type as action_type,
			COUNT(*) as total_actions,
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count,
			AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s) AND a.created_at >= ? AND a.created_at <= ?
	`, strings.Join(placeholders, ", "))

	args := make([]interface{}, 0, len(usernames)+3)
	for _, username := range usernames {
		args = append(args, username)
	}
	args = append(args, startDate, endDate)

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	query += " GROUP BY u.display_name, a.action_type"

	var results []UserActivitySummary
	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// GenerateDepartmentReport generates a report grouped by department.
func GenerateDepartmentReport(o orm.Ormer, departments []string, actionTypeFilter string) ([]map[string]interface{}, error) {
	query := `
		SELECT 
			u.department,
			COUNT(*) as total_activities,
			COUNT(DISTINCT u.id) as unique_users,
			AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE 1=1
	`

	args := []interface{}{}

	if len(departments) > 0 {
		placeholders := make([]string, len(departments))
		for i := range placeholders {
			placeholders[i] = "?"
		}
		query += fmt.Sprintf(" AND u.department IN (%s)", strings.Join(placeholders, ", "))
		for _, dept := range departments {
			args = append(args, dept)
		}
	}

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	query += " GROUP BY u.department"

	var results []orm.Params
	_, err := o.Raw(query, args...).Values(&results)
	if err != nil {
		return nil, err
	}

	maps := make([]map[string]interface{}, len(results))
	for i, p := range results {
		maps[i] = map[string]interface{}(p)
	}

	return maps, nil
}

// LogUserActivity records a new user activity in the database.
func LogUserActivity(o orm.Ormer, userId int64, actionType, resource, ipAddress string, duration int, success bool) (*UserActivity, error) {
	activity := &UserActivity{
		UserId:     userId,
		ActionType: actionType,
		Resource:   resource,
		IpAddress:  ipAddress,
		Duration:   duration,
		Success:    success,
	}
	id, err := o.Insert(activity)
	if err != nil {
		return nil, err
	}
	activity.Id = id
	return activity, nil
}

// GetUserProfile retrieves a user profile by username.
func GetUserProfile(o orm.Ormer, username string) (*UserProfile, error) {
	user := &UserProfile{Username: username}
	err := o.Read(user, "Username")
	if err != nil {
		return nil, err
	}
	return user, nil
