	}

	// Build the query
	var query strings.Builder
	query.WriteString(fmt.Sprintf(`SELECT %s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities 
		FROM user_profile u 
		LEFT JOIN user_activity a ON u.id = a.user_id 
		WHERE u.department IN (`, field))

	// Add placeholders for departments
	placeholders := make([]string, len(departments))
	for i := range departments {
		placeholders[i] = "?"
	}
	query.WriteString(strings.Join(placeholders, ", "))
	query.WriteString(`) GROUP BY ` + field)

	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		args[i] = dept
	}

	var results []orm.Params
	_, err := o.Raw(query.String(), args...).Values(&results)
