	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

type DepartmentSummary struct {
	Department   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
	ActiveUsers  int
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	var results []UserActivitySummary

	query := `
		SELECT u.display_name, a.action_type, 
		       COUNT(*) as total_actions, 
		       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count,
		       AVG(a.duration_ms) as avg_duration
		FROM user_activity a
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s)
	`

	placeholders := ""
	args := make([]interface{}, 0, len(usernames)+3)

	for i, username := range usernames {
		args = append(args, username)
		if i > 0 {
			placeholders += ", "
		}
		placeholders += "?"
	}

	query = fmt.Sprintf(query, placeholders)

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	query += " AND a.created_at >= ? AND a.created_at <= ?"
	args = append(args, startDate, endDate)

	query += " GROUP BY u.display_name, a.action_type ORDER BY u.display_name, a.action_type"

	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// GenerateDepartmentReport creates an activity report grouped by department.
func GenerateDepartmentReport(o orm.Ormer, departments []string, dateFilter string) ([]DepartmentSummary, error) {
	var results []DepartmentSummary

	query := `
		SELECT u.department,
		       COUNT(*) as total_actions,
		       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count,
		       AVG(a.duration_ms) as avg_duration,
		       COUNT(DISTINCT a.user_id) as active_users
		FROM user_activity a
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.department IN (%s)
	`

	placeholders := ""
	args := make([]interface{}, 0, len(departments)+1)

	for i, dept := range departments {
		args = append(args, dept)
		if i > 0 {
			placeholders += ", "
		}
		placeholders += "?"
	}

	query = fmt.Sprintf(query, placeholders)

	if dateFilter != "" {
		query += " AND a.created_at >= ?"
		args = append(args, dateFilter)
	}

	query += " GROUP BY u.department ORDER BY u.department"

	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

func main() {
	orm.RegisterDataBase("default", "mysql", "root:root@tcp(127.0.0.1:3306)/testdb")
	orm.RegisterModel(new(UserProfile), new(UserActivity))
	orm.RunSyncdb("default", true, false)
}

