package main

import (
	"fmt"
	"strings"
	"time"

	"github.com/beego/beego/v2/client/orm"
)

type UserProfile struct {
	Id          int64     `orm:"column(id);pk;auto"`
	Username    string    `orm:"column(username);unique"`
	DisplayName string    `orm:"column(display_name)"`
	Email       string    `orm:"column(email)"`
	Department  string    `orm:"column(department)"`
	Role        string    `orm:"column(role)"`
	CreatedAt   time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivity struct {
	Id         int64     `orm:"column(id);pk;auto"`
	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type ActivitySummary struct {
	UserId        int64
	Username      string
	TotalActions  int
	TotalDuration int
}

func GetUserActivities(userId int64, limit, offset int) ([]UserActivity, error) {
	o := orm.NewOrm()
	var activities []UserActivity
	_, err := o.QueryTable("user_activity").
		Filter("user_id", userId).
		OrderBy("-created_at").
		Limit(limit).
		Offset(offset).
		All(&activities)

	if err == orm.ErrNoRows {
		return []UserActivity{}, nil
	}

	return activities, err
}

func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) error {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	_, err := o.Insert(user)
	return err
}

func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionType string, startTime, endTime time.Time) ([]UserActivity, error) {
	var activities []UserActivity

	if len(usernames) == 0 {
		return activities, nil
	}

	placeholders := make([]string, len(usernames))
	args := make([]interface{}, 0, len(usernames)+3)
	for i, username := range usernames {
		placeholders[i] = "?"
		args = append(args, username)
	}
	args = append(args, actionType, startTime, endTime)

	query := fmt.Sprintf(`
		SELECT ua.* 
		FROM user_activity ua
		JOIN user_profile up ON ua.user_id = up.id
		WHERE up.username IN (%s)
		AND ua.action_type = ?
		AND ua.created_at BETWEEN ? AND ?
		ORDER BY ua.created_at DESC
	`, strings.Join(placeholders, ","))

	_, err := o.Raw(query, args...).QueryRows(&activities)
	if err != nil && err != orm.ErrNoRows {
		return nil, err
	}

